(1, '[{\"id\":\"f1\",\"level\":\"MTs Darussalam Cilongok\",\"desc\":\"Sekolah Menengah Pertama yang mengintegrasikan kurikulum nasional dengan nilai-nilai kepesantrenan. Menekankan pada pembentukan karakter dan penguasaan dasar-dasar ilmu agama.\",\"features\":[\"Kurikulum K13 & Merdeka\",\"Program Tahfidz Juz 30\",\"Bahasa Arab & Inggris Dasar\",\"Pembiasaan Sholat Berjamaah\"]},{\"id\":\"f2\",\"level\":\"MA Darussalam Cilongok\",\"desc\":\"Sekolah Menengah Atas dengan jurusan IPA dan IPS. Fokus pada persiapan santri menuju jenjang pendidikan tinggi dan penguasaan kitab kuning tingkat lanjut.\",\"features\":[\"Persiapan UTBK\\/SNBT\",\"Program Entrepreneurship\",\"Ekstrakurikuler Multimedia\"]}]', '[{\"id\":\"nf1\",\"name\":\"Madrasah Diniyah\",\"desc\":\"Pendidikan keagamaan berjenjang yang wajib diikuti seluruh santri.\",\"levels\":[\"Ula (Tingkat Dasar)\",\"Wustho (Tingkat Menengah)\",\"Ulya (Tingkat Atas)\"],\"subjects\":[\"Fiqh\",\"Tauhid\",\"Akhlak\",\"Nahwu Shorof\",\"Tarikh Islam\",\"Hadits\",\"Tafsir\"]},{\"id\":\"nf2\",\"name\":\"Tahfidzul Quran\",\"desc\":\"Program menghafal Al-Quran dengan target hafalan yang disesuaikan dengan kemampuan santri.\",\"programs\":[\"Tahfidz Reguler (Target 1-5 Juz)\",\"Tahfidz Takhassus (Target 30 Juz)\",\"Tahsin & Tilawah\"]}]', '[\"Pramuka\",\"Hadroh & Sholawat\",\"Kaligrafi\",\"Muhadhoroh (Public Speaking)\",\"Kewirausahaan\",\"Bahasa Asing (Arab & Inggris)\",\"Volly\",\"Futsal\",\"Tilawah\",\"Komputer\",\"Multimedia\"]', '[{\"time\":\"03.30 - 04.30\",\"activity\":\"Qiyamul Lail & Sholat Subuh\"},{\"time\":\"07.00 - 14.00\",\"activity\":\"Sekolah Formal (MTs\\/MA)\"},{\"time\":\"16.30 - 17.00\",\"activity\":\"Madrasah Diniyah\"},{\"time\":\"18.00 - 20.30\",\"activity\":\"Kegiatan Mengaji & Belajar Malam\"}]', '2026-02-17 07:59:06');

