INSERT INTO `pengumuman` (`id`, `title`, `content`, `date`, `important`, `created_at`, `updated_at`) VALUES
(1, 'Jadwal Pengajian Ramadhan', '<p class=\"ql-align-justify\">Kegiatan pada bulan ramadhan berbeda dengan hari biasanya, mulai dari intensitas ta\'limnya sampai kitab yang dikajinya juga berbeda.</p><p class=\"ql-align-justify\">Kegiatan ramadhan ini dimulai pada 1 Ramadhan - 20 Ramadhan.</p><p class=\"ql-align-justify\">Berikut jadwal kegiatan tersebut</p><p><img src=\"data:image/jpeg;base64,\"></p>', '2026-02-17', 1, '2026-02-17 05:35:23', '2026-02-17 19:01:38');
INSERT INTO `pengumuman` (`id`, `title`, `content`, `date`, `important`, `created_at`, `updated_at`) VALUES
(2, 'Libur Hari Raya Idul Fitri 1447 H', '<p>Kami informasikan kepada Bapak/ Ibu/ Wali Santri PP. Darussalam Panusupan, berdasarkan keputusan dewan pengasuh dan hasil musyawarah dewan asatidz bahwa:</p><ol><li>Libur dimulai dari tanggal 13 Maret 2026</li><li>Santri boleh pulang jika sudah melunasi administrasi sampai bulan maret</li><li>Penjemputan santri dilakukan mulai ba\'da sholat tarawih</li><li>Orang tua/ Wali diharapkan memantau kegiatan putra/putrinya selama di rumah</li><li>Libur berakhir pada tanggal 4 Maret 2026 pukul 17.30</li></ol><p>Demikian pengumuman yang kami sampaikan semoga menjadi perhatian kita bersama. Terima kasih</p>', '2026-03-03', 0, '2026-03-03 03:43:33', '2026-03-03 03:43:33');

