INSERT INTO `pojok_santri` (`id`, `title`, `content`, `author`, `author_role`, `date`, `image`, `category`, `status`, `created_at`, `updated_at`) VALUES
(2, 'Pengalaman Mengikuti Lomba Tahfidz Tingkat Kabupaten', '<p class=\"ql-align-justify\">Alhamdulillah, segala puji bagi Allah Swt yang telah memberikan kesempatan kepada saya untuk mengikuti lomba tahfidz tingkat provinsi.</p><p class=\"ql-align-justify\">Perjalanan ini dimulai dari seleksi internal pesantren, kemudian berlanjut ke tingkat kabupaten, dan akhirnya sampai di tingkat provinsi.</p><p class=\"ql-align-justify\">Banyak pengalaman berharga yang saya dapatkan selama perjalanan ini.</p>', 'Achmad', '', '2026-02-17', '', 'Prestasi', 'published', '2026-02-17 06:03:45', '2026-02-17 18:52:06'),
(4, 'Zakat Fitrah: Pengertian, Niat, Besaran, dan Hikmahnya', '<h3 class=\"ql-align-justify\"><strong>Apa Itu Zakat Fitrah?</strong></h3><p class=\"ql-align-justify\">Zakat fitrah adalah zakat wajib yang harus dikeluarkan oleh setiap muslim pada akhir bulan Ramadan sebelum Hari Raya Idul Fitri. Ibadah ini berfungsi sebagai penyuci jiwa setelah menjalankan puasa sekaligus bentuk kepedulian sosial terhadap sesama, khususnya kaum fakir dan miskin.</p><p class=\"ql-align-justify\">Tidak seperti zakat harta, zakat fitrah bersifat universal karena diwajibkan kepada setiap muslim tanpa melihat usia maupun jenis kelamin. Bahkan, seorang kepala keluarga memiliki tanggung jawab untuk membayarkan zakat bagi anggota keluarganya.</p><h3 class=\"ql-align-justify\"><strong>Hukum dan Syarat Zakat Fitrah</strong></h3><p class=\"ql-align-justify\">Hukum zakat fitrah adalah <strong>fardhu ‘ain</strong>, yang berarti wajib bagi setiap muslim yang memenuhi syarat. Adapun syarat wajibnya meliputi beragama Islam, masih hidup hingga malam Idul Fitri, serta memiliki kelebihan kebutuhan pokok untuk diri dan tanggungannya.</p><p class=\"ql-align-justify\">Dengan syarat yang relatif sederhana ini, zakat fitrah menjadi ibadah yang menjangkau hampir seluruh umat Islam.</p><h3 class=\"ql-align-justify\"><strong>Besaran Zakat Fitrah</strong></h3><p class=\"ql-align-justify\">Besaran zakat fitrah yang harus dikeluarkan adalah sebesar <strong>1 sha’</strong>, yang setara dengan sekitar <strong>2,5 hingga 3 kilogram makanan pokok</strong> seperti beras.</p><p class=\"ql-align-justify\">Di Indonesia, zakat fitrah juga sering dibayarkan dalam bentuk uang, dengan nilai yang disesuaikan dengan harga beras yang dikonsumsi sehari-hari.</p><h3 class=\"ql-align-justify\"><strong>Waktu Pembayaran Zakat Fitrah</strong></h3><p class=\"ql-align-justify\">Waktu pembayaran zakat fitrah dimulai sejak awal Ramadan. Namun, waktu yang paling utama adalah sebelum pelaksanaan shalat Idul Fitri. Jika zakat ditunaikan setelah shalat Id, maka statusnya berubah menjadi sedekah biasa, bukan lagi zakat fitrah.</p><h3 class=\"ql-align-justify\"><strong>Niat Zakat Fitrah (Arab, Latin, dan Artinya)</strong></h3><p class=\"ql-align-justify\">Niat merupakan bagian penting dalam pelaksanaan zakat fitrah. Berikut lafaz niat yang umum digunakan:</p><p class=\"ql-align-justify\"><strong>1. Niat untuk Diri Sendiri</strong></p><h3 class=\"ql-align-justify\">نَوَيْتُ أَنْ أُخْرِجَ زَكَاةَ الْفِطْرِ عَنْ نَفْسِي فَرْضًا لِلّٰهِ تَعَالَى</h3><p class=\"ql-align-justify\">Nawaitu an ukhrija zakātal fitri ‘an nafsī fardhan lillāhi ta‘ālā</p><p class=\"ql-align-justify\"><strong>Artinya:</strong></p><p class=\"ql-align-justify\"><em>“Saya niat mengeluarkan zakat fitrah untuk diri saya sendiri, fardhu karena Allah Ta’ala.”</em></p><h3 class=\"ql-align-justify\"><strong>2. Niat untuk Istri</strong></h3><h3 class=\"ql-align-justify\">نَوَيْتُ أَنْ أُخْرِجَ زَكَاةَ الْفِطْرِ عَنْ زَوْجَتِي فَرْضًا لِلّٰهِ تَعَالَى</h3><p class=\"ql-align-justify\">Nawaitu an ukhrija zakātal fitri ‘an zaujatī fardhan lillāhi ta‘ālā</p><p class=\"ql-align-justify\"><strong>Artinya:</strong></p><p class=\"ql-align-justify\"><em>“Saya niat mengeluarkan zakat fitrah untuk istri saya, fardhu karena Allah Ta’ala.”</em></p><h3 class=\"ql-align-justify\"><strong>3. Niat untuk Anak</strong></h3><h3 class=\"ql-align-justify\">نَوَيْتُ أَنْ أُخْرِجَ زَكَاةَ الْفِطْرِ عَنْ وَلَدِي فَرْضًا لِلّٰهِ تَعَالَى</h3><p class=\"ql-align-justify\">Nawaitu an ukhrija zakātal fitri ‘an waladī fardhan lillāhi ta‘ālā</p><p class=\"ql-align-justify\"><strong>Artinya:</strong></p><p class=\"ql-align-justify\"><em>“Saya niat mengeluarkan zakat fitrah untuk anak saya, fardhu karena Allah Ta’ala.”</em></p><h3 class=\"ql-align-justify\"><strong>Hikmah Zakat Fitrah</strong></h3><p class=\"ql-align-justify\">Zakat fitrah memiliki banyak hikmah yang tidak hanya berdampak secara spiritual, tetapi juga sosial. Ibadah ini membersihkan jiwa dari kesalahan selama berpuasa, sekaligus menyempurnakan ibadah Ramadan.</p><p class=\"ql-align-justify\">Selain itu, zakat fitrah membantu kaum fakir dan miskin agar mereka juga dapat merasakan kebahagiaan di Hari Raya Idul Fitri. Di sinilah nilai solidaritas dan kepedulian sosial benar-benar diwujudkan dalam kehidupan nyata.</p>', 'Achmad Rois', '', '2026-03-20', '/uploads/af1d09ba62083c4c83b5ab414968441a.png', 'Ibadah', 'published', '2026-03-20 08:19:23', '2026-03-21 06:10:31');

