INSERT INTO `sekilas_pandang` (`id`, `title`, `content`, `image`, `stats`, `updated_at`) VALUES
(1, 'Sejarah Singkat', '<p><strong>Pondok Pesantren Darussalam Panusupan</strong> didirikan di Desa Panusupan, Kecamatan Cilongok, Kabupaten Banyumas, Jawa Tengah. Pesantren ini hadir sebagai jawaban atas kebutuhan masyarakat akan pendidikan Islam yang berkualitas.</p><p>Dengan mengusung visi membentuk generasi muslim yang berilmu, berakhlak mulia, dan berdaya saing tinggi, <strong>Pondok Pesantren Darussalam Panusupan</strong> terus berkembang menjadi lembaga pendidikan Islam yang dipercaya masyarakat.</p><p><strong>Pondok Pesantren Darussalam Panusupan</strong> ini menyelenggarakan pendidikan formal (MTs dan MA) serta pendidikan kepesantrenan yang meliputi Madrasah Diniyah dan program Tahfidzul Quran.</p>', '/uploads/61155af10d2d8b41aebff09bbe3ca85f.jpg', '[{\"label\":\"Santri Aktif\",\"value\":\"100+\"},{\"label\":\"Tahun Berdiri\",\"value\":\"1990\"},{\"label\":\"Tenaga Pengajar\",\"value\":\"30+\"},{\"label\":\"Luas Area\",\"value\":\"1 Ha\"}]', '2026-03-21 06:00:21');

